// Generated by GitHub Copilot
// ── Sidebar 导航：多页模式（show/hide section）+ hash 路由 ──
/**
 * 切换到指定 section（隐藏其它），更新侧边栏激活态，写入 location.hash。
 * 切换后强制 resize 所有 Chart.js 实例（隐藏 → 显示需要重新计算尺寸）。
 */
function goSection(id) {
  const target = document.getElementById(id);
  if (!target) return;
  document.querySelectorAll('.section').forEach(s => s.classList.remove('active'));
  target.classList.add('active');
  document.querySelectorAll('.nav-link').forEach(b => {
    b.classList.remove('active');
    b.removeAttribute('aria-current');
  });
  const btn = document.querySelector(`.nav-link[onclick*="'${id}'"]`);
  if (btn) {
    btn.classList.add('active');
    btn.setAttribute('aria-current', 'page');
  }
  if (window.location.hash !== '#' + id) {
    history.replaceState(null, '', '#' + id);
  }
  window.scrollTo({ top: 0, behavior: 'instant' });
  // Chart.js 实例 resize（隐藏容器中的 canvas 尺寸为 0）
  if (window.Chart && Chart.instances) {
    Object.values(Chart.instances).forEach(c => { try { c.resize(); } catch (_) {} });
  }
}

// hash 变化时切换（支持浏览器前进/后退）
window.addEventListener('hashchange', () => {
  const id = (location.hash || '#summary').slice(1);
  goSection(id);
});

// ── 通用：货币格式化 ──
function fmtUSD(n) {
  return '$' + n.toLocaleString('en-US', { maximumFractionDigits: 0 });
}

// ── Chart.js 全局默认样式 ──
if (window.Chart) {
  Chart.defaults.font.family = "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif";
  Chart.defaults.font.size = 11;
  Chart.defaults.color = '#475569';
  Chart.defaults.plugins.legend.labels.boxWidth = 12;
  Chart.defaults.plugins.legend.labels.padding = 12;
}

